import { Elena, html, unsafeHTML } from "@elenajs/core";

/**
 * the description of the component goes here.
 *
 * @displayName DsText
 * @status alpha
 *
 * @cssprop [--ds-text-text] - Overrides the default text color.
 * @cssprop [--ds-text-bg] - Overrides the default background color.
 * @cssprop [--ds-text-font] - Overrides the default font family.
 * @cssprop [--ds-text-size] - Overrides the default font size.
 * @cssprop [--ds-text-weight] - Overrides the font weight for paragraphs.
 * @cssprop [--ds-text-weight-strong] - Overrides the font weight for h1 and h2 (default: 700).
 * @cssprop [--ds-text-weight-medium] - Overrides the font weight for h3 through h6 (default: 600).
 * @cssprop [--ds-text-line-height] - Overrides the default line height for paragraphs.
 */

export default class DsText extends Elena(HTMLElement) {
  static tagName = "ds-text";

  static props = ["variant", "tag"];

  static validTags = ["div", "h1", "h2", "h3", "h4", "h5", "h6", "p", "span"];

  /**
   * the style variant of the component.
   * @property
   * @type {"default" | "primary" | "danger"}
   */
  variant = "default";

  /**
   * the HTML tag used to render the inner element.
   * @property
   * @type {"div" | "h1" | "h2" | "h3" | "h4" | "h5" | "h6" | "p" | "span"}
   */
  tag = "div";

  /**
   * renders the html template.
   * @internal
   */
  render() {
    const safeTag = DsText.validTags.includes(this.tag) ? this.tag : "div";
    return html`
      ${unsafeHTML(`<${safeTag} class="ds-text">${this.text}</${safeTag}>`)}
    `;
  }
}

DsText.define();
